"use strict";parserFactory.register("tl.rulate.ru",()=>new RulateParser);class RulateParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelectorAll(".chapter_row");return t=[...t].filter(e=>!e.querySelector("[data-price]")),t.map(e=>util.hyperLinkToChapter(e.querySelector(".t a")))}findContent(e){return e.querySelector(".content-text")}extractTitleImpl(e){return e.querySelector("h1")}extractAuthor(e){let t=util.getElement(e,"strong",e=>"Автор:"===e.textContent);return null===t?super.extractAuthor(e):t.nextElementSibling.textContent}extractLanguage(e){return e.querySelector("html").getAttribute("lang")}extractDescription(e){return e.querySelector('meta[property="ranobe:description"]').getAttribute("content")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"#slick-slide00")||util.getFirstImgSrc(e,".slick")}addTitleToContent(e,t){let r=e.rawDom.createElement("h2");r.innerText=e.title.trim(),t.prepend(r)}}